import{_ as a,o as e,c as t,aj as l}from"./chunks/framework.Bljw9wMQ.js";const f=JSON.parse('{"title":"快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"document/index.md","filePath":"document/index.md","lastUpdated":1773994533000}'),i={name:"document/index.md"},o=l('<h1 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h1><p>ZXMange 是一款基于 Electron+React+Vite+TS 开发的桌面端项目管理工具，旨在为开发者提供一站式的多类型项目管理解决方案。</p><h2 id="安装与启动" tabindex="-1">安装与启动 <a class="header-anchor" href="#安装与启动" aria-label="Permalink to &quot;安装与启动&quot;">​</a></h2><h3 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h3><ul><li>Node.js（可选，用于部分项目功能）</li><li>GIT（可选，用于本地部署功能）</li></ul><h3 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h3><ol><li>下载安装包</li><li>运行安装程序，按照提示完成安装</li><li>启动 ZXMange 客户端</li></ol><h3 id="首次使用" tabindex="-1">首次使用 <a class="header-anchor" href="#首次使用" aria-label="Permalink to &quot;首次使用&quot;">​</a></h3><ol><li>启动软件后，进入主界面</li><li>可选择「新建项目」或「导入项目」开始使用</li><li>建好项目后请先将需要用的各类配置配置完成</li></ol><h2 id="主界面介绍" tabindex="-1">主界面介绍 <a class="header-anchor" href="#主界面介绍" aria-label="Permalink to &quot;主界面介绍&quot;">​</a></h2><ul><li><strong>左侧导航栏</strong>：项目列表、功能菜单</li><li><strong>中间区域</strong>：当前选中项目的内容展示</li><li><strong>右侧面板</strong>：项目配置、笔记等辅助功能</li><li><strong>顶部工具栏</strong>：常用操作快捷按钮</li></ul>',11),r=[o];function n(s,d,c,h,_,u){return e(),t("div",null,r)}const p=a(i,[["render",n]]);export{f as __pageData,p as default};
